def letterCombinations(digits):
    if not digits: return []
    m = {"2":"abc","3":"def","4":"ghi","5":"jkl","6":"mno","7":"pqrs","8":"tuv","9":"wxyz"}
    res = []
    def backtrack(i, cur):
        if i == len(digits): res.append(cur); return
        for c in m[digits[i]]: backtrack(i+1, cur+c)
    backtrack(0, ""); return res

